@bot.message_handler(commands=['start'])
def start(message):
    markup = types.InlineKeyboardMarkup(row_width=2)
    markup.add(types.InlineKeyboardButton("العربية 🇸🇦", callback_data="lang_ar"),
               types.InlineKeyboardButton("English 🇺🇸", callback_data="lang_en"))
    bot.send_message(message.chat.id, "مرحباً بك! اختر لغتك / Welcome! Choose your language:", reply_markup=markup)

@bot.callback_query_handler(func=lambda call: True)
def handle_query(call):
    if call.data == "lang_ar":
        markup = types.InlineKeyboardMarkup()
        markup.add(types.InlineKeyboardButton("اشترك في قناتنا على وتساب 🔗", url=WHATSAPP_CHANNEL))
        markup.add(types.InlineKeyboardButton("تحقق من الاشتراك ✅", callback_data="check_sub"))
        bot.edit_message_text("عليك الاشتراك أولاً في القناة لاستخدام البوت:", call.message.chat.id, call.message.message_id, reply_markup=markup)

    elif call.data == "check_sub":
        markup = types.InlineKeyboardMarkup()
        markup.add(types.InlineKeyboardButton("وتساب (65897 رقم)", callback_data="services"))
        bot.edit_message_text("تم التحقق! اختر الخدمة المطلوبة:", call.message.chat.id, call.message.message_id, reply_markup=markup)

    elif call.data == "services":
        markup = types.InlineKeyboardMarkup(row_width=2)
        buttons = [types.InlineKeyboardButton(c, callback_data=f"sel_{c}") for c in data.keys()]
        markup.add(*buttons)
        bot.edit_message_text("اختر الدولة المطلوبة:", call.message.chat.id, call.message.message_id, reply_markup=markup)

    elif call.data.startswith("sel_"):
        country = call.data.replace("sel_", "")
        number = random.choice(data[country])
        markup = types.InlineKeyboardMarkup()
        markup.add(types.InlineKeyboardButton("طلب كود التحقق 📩", callback_data=f"get_c_{number}"))
        markup.add(types.InlineKeyboardButton("تغيير الرقم 🔄", callback_data="services"))
        markup.add(types.InlineKeyboardButton("تغيير الدولة 🌍", callback_data="services"))
        
        text = f"الدولة: {country}\nالرقم: +{number}\n\nسعر الرقم: 2.5$"
        bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=markup)

    elif call.data.startswith("get_c_"):
        # توليد كود عشوائي 6 أرقام
        code = random.randint(111111, 999999)
        bot.answer_callback_query(call.id, "جاري طلب الكود...")
        bot.send_message(call.message.chat.id, f"وصل كود التحقق للرقم!\n\nكود الواتساب: {code}")

bot.infinity_polling()
